import * as XLSX from 'xlsx';
import dayjs from 'dayjs';
import customParseFormat from 'dayjs/plugin/customParseFormat.js';

dayjs.extend(customParseFormat);

export const processCombinedData = (csvData, excelRaw, proyectadoManual = 239000) => {
  if (!csvData || !excelRaw) return null;

  try {
    // --- 1. PROCESAR EXCEL (EASY DOCKING) ---
    const workbook = XLSX.read(excelRaw, { type: 'array' });
    const sheet = workbook.Sheets[workbook.SheetNames[0]];

    // Leemos como matriz para detectar las columnas por posición
    const rows = XLSX.utils.sheet_to_json(sheet, { header: 1 });
    const headerRow = rows[3] || []; // Fila 4 (Índice 3)

    // Mapeamos los datos a objetos usando los nombres de la fila 4
    const dataRows = rows.slice(4).map(row => {
      let obj = {};
      headerRow.forEach((header, index) => {
        if (header) obj[String(header).trim()] = row[index];
      });
      return obj;
    });

    // Filtramos: Solo DESCARGA y Acción add
    const easyDockingClean = dataRows.filter(item => {
      const operacion = String(item['TIPO DE OPERACION'] || "").toUpperCase();
      const accion = String(item['Accion'] || item['ACCION'] || "").toLowerCase();
      return operacion.includes("DESCARGA") && accion === "add";
    });

    // SUMA DE UNIDADES (ARRIBADOS)
    const totalArribadosFisicos = easyDockingClean.reduce((acc, curr) => {
      const valor = curr['CANT PAQUETES'] || curr['CANT PAQUETES'] || 0;
      return acc + (parseFloat(valor) || 0);
    }, 0);

    // --- 2. PROCESAR CSV (TMS) ---
    const totalPiezasSistema = csvData.length;

    // Buscamos la columna de bipeo (flexible por si cambia el nombre)
    const colBipeo = Object.keys(csvData[0] || {}).find(k => 
      k.toLowerCase().includes("labeling") && k.toLowerCase().includes("printed")
    );

    // --- 3. LÓGICA DE TIEMPO (CIERRE 22:00) ---
    const ahora = dayjs();
    const horaCierre = dayjs().set('hour', 22).set('minute', 0).set('second', 0);
    let horasRestantes = horaCierre.diff(ahora, 'hour', true);
    if (horasRestantes <= 0) horasRestantes = 0.5;

    // FÓRMULA EXCEL: (Proyectado - Bipeado) / Horas_Restantes
    const objXHora = Math.round((proyectadoManual - totalPiezasSistema) / horasRestantes);

    // --- 4. GRÁFICA (05:00 A 23:00) ---
    const franjas = [];
    for (let i = 5; i <= 23; i++) {
      franjas.push(`${i.toString().padStart(2, '0')}:00`);
    }

    const chartMap = {};
    franjas.forEach(h => chartMap[h] = { hora: h, arribo: 0, bipeo: 0 });

    // Llenar Arribos (Excel)
    easyDockingClean.forEach(row => {
      const fechaRaw = row['Fecha y Hora'];
      if (fechaRaw) {
        const hora = dayjs(fechaRaw).format('HH:00');
        if (chartMap[hora]) {
          chartMap[hora].arribo += (parseFloat(row['CANT PAQUETES'] || row['CANT PAQUETES']) || 0);
        }
      }
    });

    // Llenar Bipeos (CSV)
    csvData.forEach(row => {
      const fechaRaw = row[colBipeo];
      if (fechaRaw) {
        const hora = dayjs(fechaRaw, "DD/MM/YYYY HH:mm:ss").format('HH:00');
        if (chartMap[hora]) chartMap[hora].bipeo++;
      }
    });

    // --- 5. RETORNO DE DATOS ---
    return {
      kpis: {
        proyectado: proyectadoManual.toLocaleString(),
        arribados: totalArribadosFisicos.toLocaleString(),
        total: totalPiezasSistema.toLocaleString(),
        descargaHora: objXHora > 0 ? objXHora.toLocaleString() : "0",
        arribadoBipeado: (totalArribadosFisicos - totalPiezasSistema).toLocaleString(),
        proyectadoBipeado: (proyectadoManual - totalPiezasSistema).toLocaleString(),
        pArribado: Math.round((totalArribadosFisicos / proyectadoManual) * 100) || 0,
        pBipeo: Math.round((totalPiezasSistema / proyectadoManual) * 100) || 0,
        velocidadReal: 90
      },
      chartData: Object.values(chartMap),
      tableData: franjas.map(h => ({
        intervalo: h,
        etiquetado: Math.round(proyectadoManual / 19),
        piezas: chartMap[h].bipeo,
        usuarios: 12
      })),
      matrix: {
        chasis: easyDockingClean.filter(d => String(d['TRANSPORTE'] || "").includes("Chasis")).length,
        camioneta: easyDockingClean.filter(d => String(d['TRANSPORTE'] || "").toLowerCase().includes("camioneta")).length,
        semi: easyDockingClean.filter(d => String(d['TRANSPORTE'] || "").includes("Semi")).length
      }
    };
  } catch (error) {
    console.error("Error crítico en el procesador:", error);
    return null;
  }
};
